#!/bin/bash
# Framework de tests complet

# bats-core est recommandé en production
# npm install -g bats

# Fichier: tests/test_functions.bats
#!/usr/bin/env bats

setup() {
    # Charger les fonctions à tester
    source "${BATS_TEST_DIRNAME}/../lib/utils.sh"

    # Créer un répertoire temporaire
    export TEST_DIR="$(mktemp -d)"
}

teardown() {
    rm -rf "$TEST_DIR"
}

@test "maximum retourne le plus grand" {
    result=$(maximum 5 3)
    [ "$result" -eq 5 ]
}

@test "maximum avec nombres égaux" {
    result=$(maximum 7 7)
    [ "$result" -eq 7 ]
}

@test "nettoyer_entree rejette les entrées vides" {
    run nettoyer_entree ""
    [ "$status" -eq 1 ]
}

@test "nettoyer_entree tronque à 20 caractères" {
    result=$(nettoyer_entree "$(printf 'a%.0s' {1..30})")
    [ ${#result} -le 20 ]
}
```

