OP=""; A=""; B=""

while [[ $# -gt 0 ]]; do
    case $1 in
        --op) OP=$2; shift 2 ;;
        --a)  A=$2;  shift 2 ;;
        --b)  B=$2;  shift 2 ;;
        -h)   echo "Usage : $0 --op add|sub|mul|div --a N --b N"; exit 0 ;;
        *)    echo "Option inconnue : $1" >&2; exit 1 ;;
    esac
done

[ -z "$OP" ] || [ -z "$A" ] || [ -z "$B" ] && {
    echo "Erreur : --op, --a et --b sont requis" >&2; exit 1
}

case $OP in
    add) echo "$A + $B = $(echo "$A + $B" | bc)" ;;
    sub) echo "$A - $B = $(echo "$A - $B" | bc)" ;;
    mul) echo "$A × $B = $(echo "$A * $B" | bc)" ;;
    div) echo "$A ÷ $B = $(echo "scale=4; $A / $B" | bc)" ;;
    *)   echo "Opération inconnue : $OP" >&2; exit 1 ;;
esac
